checker_dsl:
EXISTS (`class C`) {
  AND {
    (`class C is not abstract`),
    NOT { (`class C is java.io.OutputStream or java.io.FilterOutputStream`) },
    EXISTS (`supertype S`) {
      AND {
        (`supertype S is a supertype of class C`),
        (`supertype S is java.io.OutputStream or java.io.FilterOutputStream`)
      }
    },
    EXISTS (`method M`) {
      AND {
        (`method M is declared in class C`),
        (`method M has name "write"`),
        (`method M has exactly 1 parameter`),
        (`the first parameter of method M has primitive type int`),
        EXISTS (`method M2`) {
          AND {
            (`method M2 is inherited by class C`),
            (`method M2 has name "write"`),
            (`method M2 has exactly 3 parameters`),
            EXISTS (`declaring type DT`) {
              AND {
                (`declaring type DT is the declaring type of method M2`),
                (`declaring type DT is java.io.OutputStream or java.io.FilterOutputStream`)
              }
            }
          }
        },
        EXISTS (`method call MC`) {
          AND {
            (`method call MC is inside method M`),
            (`the called method in method call MC has name "write"`)
          }
        }
      }
    }
  }
}
